public class CustomScreen extends Screen {
    public CustomScreen() {
        super(Text.literal("自定义屏幕"));
    }
    @Override
    protected void init() {
        super.init();
    }
    @Override
    public void render(DrawContext context, int mouseX, int mouseY, float delta) {
        this.renderBackground(context);
        context.drawCenteredTextWithShadow(this.textRenderer, this.title, this.width / 2, 20, 0xFFFFFF);
        super.render(context, mouseX, mouseY, delta);
    }
    @Override
    public boolean shouldPause() { return false; }
}

this.addDrawableChild(ButtonWidget.builder(Text.literal("点击我"), button -> {
    MinecraftClient.getInstance().player.sendMessage(Text.literal("按钮被点击"), false);
}).dimensions(width / 2 - 50, height / 2 - 10, 100, 20).build());

TextFieldWidget textField = new TextFieldWidget(this.textRenderer, width / 2 - 75, height / 2 - 40, 150, 20, Text.literal(""));
textField.setMaxLength(32);
textField.setChangedListener(text -> {
    System.out.println("输入: " + text);
});
this.addDrawableChild(textField);

public class CustomHandledScreen extends HandledScreen<CustomScreenHandler> {
    private static final Identifier TEXTURE = new Identifier("modid", "textures/gui/custom.png");
    public CustomHandledScreen(CustomScreenHandler handler, PlayerInventory inventory, Text title) {
        super(handler, inventory, title);
        this.backgroundWidth = 176;
        this.backgroundHeight = 166;
    }
    @Override
    protected void drawBackground(DrawContext context, float delta, int mouseX, int mouseY) {
        int x = (width - backgroundWidth) / 2;
        int y = (height - backgroundHeight) / 2;
        context.drawTexture(TEXTURE, x, y, 0, 0, backgroundWidth, backgroundHeight);
    }
}

public class CustomScreenHandler extends ScreenHandler {
    public CustomScreenHandler(int syncId, PlayerInventory playerInventory) {
        super(ModScreenHandlers.CUSTOM, syncId);
        // 添加槽位
    }
    @Override
    public ItemStack quickMove(PlayerEntity player, int slot) {
        return ItemStack.EMPTY;
    }
    @Override
    public boolean canUse(PlayerEntity player) {
        return true;
    }
}

public class ModScreenHandlers {
    public static final ScreenHandlerType<CustomScreenHandler> CUSTOM = new ScreenHandlerType<>(CustomScreenHandler::new);
    public static void register() {
        Registry.register(Registries.SCREEN_HANDLER, new Identifier("modid", "custom"), CUSTOM);
    }
}
